     1→import { promises as fs, watch, FSWatcher } from 'fs';
     2→import { join, dirname, basename } from 'path';
     3→import { EventEmitter } from 'events';
     4→import { createHash } from 'crypto';
     5→import {
     6→  CategoryConfiguration,
     7→  validateCategoryConfiguration,
     8→  getValidationErrors,
     9→  AttributeRole,
    10→} from './category-config-schema';
    11→import {
    12→  ProcessingConfigTuning,
    13→  validateProcessingConfigTuning,
    14→  getProcessingConfigErrors,
    15→} from './processing-config-schema';
    16→
    17→/**
    18→ * Configuration loader with hot-reload capability
    19→ * Monitors configuration files for changes and validates them automatically
    20→ */
    21→
    22→export interface ConfigLoadOptions {
    23→  configDir?: string;
    24→  enableHotReload?: boolean;
    25→  validateOnLoad?: boolean;
    26→  compileRules?: boolean;
    27→  cacheTtlMs?: number;
    28→  backupOnChange?: boolean;
    29→}
    30→
    31→export interface ConfigLoadResult<T> {
    32→  config: T;
    33→  hash: string;
    34→  lastModified: Date;
    35→  validationPassed: boolean;
    36→  validationErrors: string[];
    37→  loadTime: number;
    38→}
    39→
    40→export interface CompiledRule {
    41→  category: string;
    42→  subtype: string;
    43→  tier: 'high' | 'medium' | 'low';
    44→  pattern: RegExp;
    45→  weight: number;
    46→  parallelSafe: boolean;
    47→}
    48→
    49→export interface AttributeInfluenceMatrix {
    50→  [category: string]: {
    51→    [attribute: string]: {
    52→      role: AttributeRole;
    53→      bonus: number;
    54→      cap: number;
    55→    };
    56→  };
    57→}
    58→
    59→// eslint-disable-next-line @typescript-eslint/no-unsafe-declaration-merging
    60→export class ConfigurationLoader extends EventEmitter {
    61→  private configDir: string;
    62→  private enableHotReload: boolean;
    63→  private validateOnLoad: boolean;
    64→  private compileRules: boolean;
    65→  private cacheTtlMs: number;
    66→  private backupOnChange: boolean;
    67→
    68→  private watchers: Map<string, FSWatcher> = new Map();
    69→  private configCache: Map<string, ConfigLoadResult<unknown>> = new Map();
    70→  private lastHashes: Map<string, string> = new Map();
    71→
    72→  constructor(options: ConfigLoadOptions = {}) {
    73→    super();
    74→
    75→    this.configDir = options.configDir || join(process.cwd(), 'config');
    76→    this.enableHotReload = options.enableHotReload ?? true;
    77→    this.validateOnLoad = options.validateOnLoad ?? true;
    78→    this.compileRules = options.compileRules ?? true;
    79→    this.cacheTtlMs = options.cacheTtlMs ?? 60000; // 1 minute default
    80→    this.backupOnChange = options.backupOnChange ?? true;
    81→
    82→    // Clean up watchers on process exit
    83→    process.on('exit', () => this.cleanup());
    84→    process.on('SIGINT', () => this.cleanup());
    85→    process.on('SIGTERM', () => this.cleanup());
    86→  }
    87→
    88→  /**
    89→   * Load category configuration with validation and hot-reload setup
    90→   */
    91→  async loadCategoryConfiguration(
    92→    filename: string = 'email-categorizer-config.json'
    93→  ): Promise<ConfigLoadResult<CategoryConfiguration>> {
    94→    const filepath = join(this.configDir, filename);
    95→
    96→    try {
    97→      const startTime = Date.now();
    98→
    99→      // Check cache first
   100→      const cached = this.getCachedConfig<CategoryConfiguration>(filepath);
   101→      if (cached) {
   102→        return cached;
   103→      }
   104→
   105→      // Load and parse configuration
   106→      const fileContent = await fs.readFile(filepath, 'utf-8');
   107→      const hash = this.calculateHash(fileContent);
   108→      const stats = await fs.stat(filepath);
   109→
   110→      let config: unknown;
   111→      try {
   112→        config = JSON.parse(fileContent);
   113→      } catch (parseError) {
   114→        throw new Error(
   115→          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
   116→        );
   117→      }
   118→
   119→      // Validate configuration
   120→      let validationPassed = true;
   121→      let validationErrors: string[] = [];
   122→      let validatedConfig: CategoryConfiguration;
   123→
   124→      if (this.validateOnLoad) {
   125→        try {
   126→          validatedConfig = validateCategoryConfiguration(config);
   127→
   128→          // Additional custom validation
   129→          validationErrors = await this.validateCategoryConfigurationCustom(validatedConfig);
   130→          validationPassed = validationErrors.length === 0;
   131→        } catch (error) {
   132→          console.error('Configuration validation failed:', error);
   133→          validationPassed = false;
   134→          validationErrors = getValidationErrors(config);
   135→          validatedConfig = config as CategoryConfiguration; // Use unvalidated config for error reporting
   136→        }
   137→      } else {
   138→        validatedConfig = config as CategoryConfiguration;
   139→      }
   140→
   141→      // Compile rules if enabled
   142→      if (this.compileRules && validationPassed) {
   143→        validatedConfig.compiledRules = await this.compileConfigurationRules(validatedConfig);
   144→        validatedConfig.attributeMatrix = await this.computeAttributeMatrix(validatedConfig);
   145→      }
   146→
   147→      // Update metadata
   148→      validatedConfig.hash = hash;
   149→      validatedConfig.lastModified = stats.mtime;
   150→      validatedConfig.validationPassed = validationPassed;
   151→      validatedConfig.validationErrors = validationErrors;
   152→
   153→      // Performance metrics
   154→      if (!validatedConfig.performanceMetrics) {
   155→        validatedConfig.performanceMetrics = {};
   156→      }
   157→      validatedConfig.performanceMetrics.lastValidationTimeMs = Date.now() - startTime;
   158→
   159→      const result: ConfigLoadResult<CategoryConfiguration> = {
   160→        config: validatedConfig,
   161→        hash,
   162→        lastModified: stats.mtime,
   163→        validationPassed,
   164→        validationErrors,
   165→        loadTime: Date.now() - startTime,
   166→      };
   167→
   168→      // Cache the result
   169→      this.setCachedConfig(filepath, result);
   170→      this.lastHashes.set(filepath, hash);
   171→
   172→      // Set up hot-reload if enabled
   173→      if (this.enableHotReload && !this.watchers.has(filepath)) {
   174→        await this.setupHotReload(filepath, 'category');
   175→      }
   176→
   177→      // Create backup if enabled
   178→      if (this.backupOnChange && validationPassed) {
   179→        await this.createBackup(filepath, hash);
   180→      }
   181→
   182→      this.emit('configLoaded', { type: 'category', filepath, result });
   183→
   184→      return result;
   185→    } catch (error) {
   186→      this.emit('configError', { type: 'category', filepath, error: error as Error });
   187→      throw new Error(
   188→        `Failed to load category configuration from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
   189→      );
   190→    }
   191→  }
   192→
   193→  /**
   194→   * Load processing configuration with validation
   195→   */
   196→  async loadProcessingConfiguration(
   197→    filename: string = 'processing-config.json'
   198→  ): Promise<ConfigLoadResult<ProcessingConfigTuning>> {
   199→    const filepath = join(this.configDir, filename);
   200→
   201→    try {
   202→      const startTime = Date.now();
   203→
   204→      // Check cache first
   205→      const cached = this.getCachedConfig<ProcessingConfigTuning>(filepath);
   206→      if (cached) {
   207→        return cached;
   208→      }
   209→
   210→      // Load and parse configuration
   211→      const fileContent = await fs.readFile(filepath, 'utf-8');
   212→      const hash = this.calculateHash(fileContent);
   213→      const stats = await fs.stat(filepath);
   214→
   215→      let config: unknown;
   216→      try {
   217→        config = JSON.parse(fileContent);
   218→      } catch (parseError) {
   219→        throw new Error(
   220→          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
   221→        );
   222→      }
   223→
   224→      // Validate configuration
   225→      let validationPassed = true;
   226→      let validationErrors: string[] = [];
   227→      let validatedConfig: ProcessingConfigTuning;
   228→
   229→      if (this.validateOnLoad) {
   230→        try {
   231→          validatedConfig = validateProcessingConfigTuning(config);
   232→
   233→          // Additional custom validation
   234→          validationErrors = await this.validateProcessingConfigurationCustom(validatedConfig);
   235→          validationPassed = validationErrors.length === 0;
   236→        } catch (error) {
   237→          console.error('Processing configuration validation failed:', error);
   238→          validationPassed = false;
   239→          validationErrors = getProcessingConfigErrors(config);
   240→          validatedConfig = config as ProcessingConfigTuning; // Use unvalidated config for error reporting
   241→        }
   242→      } else {
   243→        validatedConfig = config as ProcessingConfigTuning;
   244→      }
   245→
   246→      const result: ConfigLoadResult<ProcessingConfigTuning> = {
   247→        config: validatedConfig,
   248→        hash,
   249→        lastModified: stats.mtime,
   250→        validationPassed,
   251→        validationErrors,
   252→        loadTime: Date.now() - startTime,
   253→      };
   254→
   255→      // Cache the result
   256→      this.setCachedConfig(filepath, result);
   257→      this.lastHashes.set(filepath, hash);
   258→
   259→      // Set up hot-reload if enabled
   260→      if (this.enableHotReload && !this.watchers.has(filepath)) {
   261→        await this.setupHotReload(filepath, 'processing');
   262→      }
   263→
   264→      this.emit('configLoaded', { type: 'processing', filepath, result });
   265→
   266→      return result;
   267→    } catch (error) {
   268→      this.emit('configError', { type: 'processing', filepath, error: error as Error });
   269→      throw new Error(
   270→        `Failed to load processing configuration from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
   271→      );
   272→    }
   273→  }
   274→
   275→  /**
   276→   * Load domain sources configuration
   277→   */
   278→  async loadDomainSources(
   279→    filename: string = 'domain-sources.json'
   280→  ): Promise<ConfigLoadResult<Record<string, string[]>>> {
   281→    const filepath = join(this.configDir, filename);
   282→
   283→    try {
   284→      const startTime = Date.now();
   285→
   286→      // Check cache first
   287→      const cached = this.getCachedConfig<Record<string, string[]>>(filepath);
   288→      if (cached) {
   289→        return cached;
   290→      }
   291→
   292→      // Load and parse configuration
   293→      const fileContent = await fs.readFile(filepath, 'utf-8');
   294→      const hash = this.calculateHash(fileContent);
   295→      const stats = await fs.stat(filepath);
   296→
   297→      let config: Record<string, string[]>;
   298→      try {
   299→        config = JSON.parse(fileContent);
   300→      } catch (parseError) {
   301→        throw new Error(
   302→          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
   303→        );
   304→      }
   305→
   306→      // Basic validation for domain sources
   307→      const validationErrors = this.validateDomainSources(config);
   308→      const validationPassed = validationErrors.length === 0;
   309→
   310→      const result: ConfigLoadResult<Record<string, string[]>> = {
   311→        config,
   312→        hash,
   313→        lastModified: stats.mtime,
   314→        validationPassed,
   315→        validationErrors,
   316→        loadTime: Date.now() - startTime,
   317→      };
   318→
   319→      // Cache the result
   320→      this.setCachedConfig(filepath, result);
   321→      this.lastHashes.set(filepath, hash);
   322→
   323→      // Set up hot-reload if enabled
   324→      if (this.enableHotReload && !this.watchers.has(filepath)) {
   325→        await this.setupHotReload(filepath, 'domains');
   326→      }
   327→
   328→      this.emit('configLoaded', { type: 'domains', filepath, result });
   329→
   330→      return result;
   331→    } catch (error) {
   332→      this.emit('configError', { type: 'domains', filepath, error: error as Error });
   333→      throw new Error(
   334→        `Failed to load domain sources from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
   335→      );
   336→    }
   337→  }
   338→
   339→  /**
   340→   * Reload a specific configuration file
   341→   */
   342→  async reloadConfiguration(filepath: string): Promise<void> {
   343→    // Clear cache for this file
   344→    this.configCache.delete(filepath);
   345→
   346→    // Determine config type and reload
   347→    const filename = basename(filepath);
   348→
   349→    if (filename.includes('email-categorizer-config') || filename.includes('category')) {
   350→      await this.loadCategoryConfiguration(filename);
   351→    } else if (filename.includes('processing-config') || filename.includes('processing')) {
   352→      await this.loadProcessingConfiguration(filename);
   353→    } else if (filename.includes('domain-sources') || filename.includes('domain')) {
   354→      await this.loadDomainSources(filename);
   355→    } else {
   356→      throw new Error(`Unknown configuration type for file: ${filename}`);
   357→    }
   358→  }
   359→
   360→  /**
   361→   * Get configuration hash for change detection
   362→   */
   363→  getConfigurationHash(filepath: string): string | undefined {
   364→    return this.lastHashes.get(filepath);
   365→  }
   366→
   367→  /**
   368→   * Check if configuration has changed
   369→   */
   370→  async hasConfigurationChanged(filepath: string): Promise<boolean> {
   371→    try {
   372→      const content = await fs.readFile(filepath, 'utf-8');
   373→      const currentHash = this.calculateHash(content);
   374→      const lastHash = this.lastHashes.get(filepath);
   375→      return currentHash !== lastHash;
   376→    } catch {
   377→      return true; // Assume changed if can't read
   378→    }
   379→  }
   380→
   381→  /**
   382→   * Cleanup watchers and resources
   383→   */
   384→  cleanup(): void {
   385→    for (const [filepath, watcher] of Array.from(this.watchers.entries())) {
   386→      try {
   387→        watcher.close();
   388→      } catch (error) {
   389→        console.warn(`Failed to close watcher for ${filepath}:`, error);
   390→      }
   391→    }
   392→    this.watchers.clear();
   393→    this.configCache.clear();
   394→    this.lastHashes.clear();
   395→  }
   396→
   397→  // Private methods
   398→
   399→  private getCachedConfig<T>(filepath: string): ConfigLoadResult<T> | undefined {
   400→    const cached = this.configCache.get(filepath);
   401→    if (!cached) return undefined;
   402→
   403→    const age = Date.now() - cached.loadTime;
   404→    if (age > this.cacheTtlMs) {
   405→      this.configCache.delete(filepath);
   406→      return undefined;
   407→    }
   408→
   409→    return cached as ConfigLoadResult<T>;
   410→  }
   411→
   412→  private setCachedConfig<T>(filepath: string, result: ConfigLoadResult<T>): void {
   413→    this.configCache.set(filepath, result);
   414→  }
   415→
   416→  private calculateHash(content: string): string {
   417→    return createHash('sha256').update(content).digest('hex');
   418→  }
   419→
   420→  private async setupHotReload(filepath: string, configType: string): Promise<void> {
   421→    try {
   422→      const watcher = watch(filepath, { persistent: false });
   423→
   424→      watcher.on('change', async () => {
   425→        try {
   426→          if (await this.hasConfigurationChanged(filepath)) {
   427→            this.emit('configChanging', { type: configType, filepath });
   428→            await this.reloadConfiguration(filepath);
   429→            this.emit('configChanged', { type: configType, filepath });
   430→          }
   431→        } catch (error) {
   432→          this.emit('configError', { type: configType, filepath, error: error as Error });
   433→        }
   434→      });
   435→
   436→      watcher.on('error', (error: Error) => {
   437→        this.emit('configError', { type: configType, filepath, error });
   438→      });
   439→
   440→      this.watchers.set(filepath, watcher);
   441→    } catch (error) {
   442→      console.warn(`Failed to setup hot-reload for ${filepath}:`, error);
   443→    }
   444→  }
   445→
   446→  private async createBackup(filepath: string, hash: string): Promise<void> {
   447→    try {
   448→      const backupDir = join(dirname(filepath), '.backups');
   449→      await fs.mkdir(backupDir, { recursive: true });
   450→
   451→      const filename = basename(filepath);
   452→      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
   453→      const backupPath = join(backupDir, `${filename}.${timestamp}.${hash.slice(0, 8)}.backup`);
   454→
   455→      await fs.copyFile(filepath, backupPath);
   456→
   457→      // Keep only last 10 backups
   458→      const backups = await fs.readdir(backupDir);
   459→      const fileBackups = backups
   460→        .filter((f: string) => f.startsWith(filename))
   461→        .sort()
   462→        .reverse();
   463→
   464→      for (const backup of fileBackups.slice(10)) {
   465→        await fs.unlink(join(backupDir, backup));
   466→      }
   467→    } catch (error) {
   468→      console.warn(`Failed to create backup for ${filepath}:`, error);
   469→    }
   470→  }
