   544→  private async computeAttributeMatrix(config: CategoryConfiguration): Promise<AttributeInfluenceMatrix> {
   545→    const startTime = Date.now();
   546→    const matrix: AttributeInfluenceMatrix = {};
   547→
   548→    // Build attribute influence matrix from attributeRelevance configuration
   549→    const attributeRelevance = config.processingConfig.attributeRelevance;
   550→
   551→    for (const [categoryName, categoryConfig] of Object.entries(attributeRelevance)) {
   552→      if (categoryName === '_roles_legend') continue;
   553→
   554→      // Type guard to ensure we have the correct structure
   555→      if (typeof categoryConfig === 'object' && categoryConfig !== null && 'categoryRoles' in categoryConfig) {
   556→        matrix[categoryName] = {};
   557→
   558→        // Process category-level roles
